import React, { useEffect, useRef, useState } from 'react';

import { FloatingNavigationProps } from './FloatingNavigation.types';

import './FloatingNavigation.scss';
import { classNames } from ':helpers/classnames';
import { FloatingNavigationItem } from './FloatingNavigationItem';

export const FloatingNavigation: React.FC<FloatingNavigationProps> = ({
	className,
	dataTestId = 'FloatingNavigation',
	value,
	anchorAttribute = 'id',
	scrollOffsetTop = 100,
	scrollOffsetBottom = 100,
	sticky,
	onClick,
	onChange,
	...rest
}) => {
	const [activeAnchor, setActiveAnchor] = useState<string>('');
	const [isScrolling, setIsScrolling] = useState(false);
	const isFirstRender = useRef(true);

	const getAnchorByAttribute = (item: Element) => item?.getAttribute(`${anchorAttribute}`);

	const handleScroll = () => {
		if (isScrolling) return;
		const anchors = document.querySelectorAll(`[${anchorAttribute}]`);
		let active = '';

		anchors.forEach(anchor => {
			const rect = anchor.getBoundingClientRect();

			if (rect.top <= scrollOffsetTop && rect.bottom >= scrollOffsetBottom) {
				active = getAnchorByAttribute(anchor) || '';
			}
		});

		setActiveAnchor(active);
	};

	const isActive = (anchor: string) => {
		if (activeAnchor === anchor) return true;

		const parent = value.find(item => item.anchor === anchor);
		if (parent?.children?.some(child => child.anchor === activeAnchor)) {
			return true;
		}

		return false;
	};

	const scrollToElementWithCallback = (
		// https://github.com/w3c/csswg-drafts/issues/3744
		element: HTMLElement,
		callback: () => void,
		arg?: boolean | ScrollIntoViewOptions,
	): void => {
		setIsScrolling(true);
		const eventListenerCB = () => {
			clearTimeout(timer);
			timer = setTimeout(timerCB, 50);
		};

		const timerCB = () => {
			setIsScrolling(false);
			callback();
			document.removeEventListener('scroll', eventListenerCB);
		};

		let timer = setTimeout(timerCB, 100);

		document.addEventListener('scroll', eventListenerCB);

		element.scrollIntoView(arg);
	};

	const handleKeyDown = (event: React.KeyboardEvent, anchor: string) => {
		if (event.key === 'Enter') {
			event.preventDefault();
			handleAnchorClick(event, anchor);
		}
	};

	const handleAnchorClick = (event, anchor: string) => {
		if (onClick) {
			onClick(event, anchor);
		} else {
			defaultAnchorOnClick(event, anchor);
		}
	};

	const defaultAnchorOnClick = (event, anchor) => {
		const anchorElement = document.querySelector(`[${anchorAttribute}="${anchor}"]`) as HTMLElement;
		scrollToElementWithCallback(
			anchorElement,
			() => {
				setActiveAnchor(anchor);
			},
			{ behavior: 'smooth' },
		);
	};

	useEffect(() => {
		if (isFirstRender.current) {
			const firstActive = value.find(item => {
				const element = document.querySelector(`[${anchorAttribute}="${item.anchor}"]`);
				if (!element) return false;
				const rect = element.getBoundingClientRect();
				return rect.top <= scrollOffsetTop && rect.bottom >= scrollOffsetBottom;
			});
			if (firstActive) {
				setActiveAnchor(firstActive.anchor);
			}
			isFirstRender.current = false;
		}
	}, [value, anchorAttribute, scrollOffsetTop, scrollOffsetBottom]);

	useEffect(() => {
		if (activeAnchor) onChange(activeAnchor);
	}, [activeAnchor, onChange]);

	useEffect(() => {
		window.addEventListener('scroll', handleScroll);
		return () => {
			window.removeEventListener('scroll', handleScroll);
		};
	}, [isScrolling, handleScroll]);

	return (
		<nav
			role="list"
			data-testid={dataTestId}
			className={classNames(className, 'dsb_floatingnav', sticky && 'dsb_floatingnav-sticky')}
			{...rest}
		>
			{value.map(item => (
				<FloatingNavigationItem
					key={item.anchor}
					label={item.value}
					active={isActive(item.anchor)}
					onClick={event => handleAnchorClick(event, item.anchor)}
					onKeyDown={event => handleKeyDown(event, item.anchor)}
				>
					{item?.children?.map((subitem, index) => (
						<FloatingNavigationItem
							key={subitem.anchor}
							label={subitem.value}
							active={activeAnchor === subitem.anchor || (item.anchor === activeAnchor && !index)}
							onClick={event => handleAnchorClick(event, subitem.anchor)}
							onKeyDown={event => handleKeyDown(event, subitem.anchor)}
							child
						/>
					))}
				</FloatingNavigationItem>
			))}
		</nav>
	);
};
